def file_name_check(file_name):
    # Count dots in the file name
    dot_count = file_name.count('.')
    if dot_count != 1:
        return 'No'

    # Split into name and extension parts
    pre_dot, post_dot = file_name.split('.')

    # Check extension validity
    valid_extensions = {'txt', 'exe', 'dll'}
    if post_dot not in valid_extensions:
        return 'No'

    # Check pre-dot part rules
    if not pre_dot:
        return 'No'

    if not pre_dot[0].isalpha():
        return 'No'

    # Count digits in the pre-dot part
    digit_count = sum(c.isdigit() for c in pre_dot)
    if digit_count > 3:
        return 'No'

    return 'Yes'
